Describe 'Package generation' { BeforeAll { $script:out=Join-Path $TestDrive 'out with spaces'; & $PSScriptRoot/../Generate-Package.ps1 -ProfilePath $PSScriptRoot/../profiles/windchill-12.1.2.json -OutputDirectory $script:out; $script:name='wc-12.1.2-foundation-build-0.1.0' } It 'creates deterministic outputs and required files' { Test-Path (Join-Path $out "$name.zip") | Should -BeTrue; Test-Path (Join-Path $out "$name.zip.sha256") | Should -BeTrue; foreach($f in 'Start-Foundation-Build.ps1','Resume-Foundation-Build.ps1','Clean-Foundation-Build.ps1','Test-Prerequisites.ps1','Vagrantfile','config.json','secrets.example.json','README.md'){ Test-Path (Join-Path $out "$name/$f") | Should -BeTrue } } It 'excludes media and secrets' { Get-ChildItem -Recurse (Join-Path $out $name) | % Name | Should -Not -Contain 'secrets.json'; Get-ChildItem -Recurse (Join-Path $out $name) | % Name | Should -Not -Contain 'LINUX.X64_193000_db_home.zip' } }
